mapper.select:
SELECT EVENT_ID as id, TITLE as title, TO_CHAR(START_DT, 'YYYY-MM-DD') as startDt, /* 종료일에 +1을 해서 달력에 이틀치로 보이게 만듭니다 */ TO_CHAR(END_DT + 1, 'YYYY-MM-DD') as endDt, 'EVENT' as itemType FROM EVENTS WHERE PROJ_ID = #{projId} AND START_DT BETWEEN TO_DATE(#{startDate}, 'YYYY-MM-DD') AND TO_DATE(#{endDate}, 'YYYY-MM-DD')
UNION ALL
/* 공휴일은 하루짜리이므로 그대로 둡니다 */ SELECT HLD_ID as id, HLD_NAME as title, TO_CHAR(HLD_DATE, 'YYYY-MM-DD') as startDt, TO_CHAR(HLD_DATE + 1, 'YYYY-MM-DD') as endDt, 'HOLIDAY' as itemType FROM NATIONAL_HOLIDAYS WHERE HLD_DATE BETWEEN TO_DATE(#{startDate}, 'YYYY-MM-DD') AND TO_DATE(#{endDate}, 'YYYY-MM-DD')

mapper.delete:
DELETE FROM PROJ_MEMBERS 
WHERE PROJ_ID = #{projId} 
  AND USER_ID = #{userId}
